# Text utilities module for string formatting and transformations

def reverse(s: str) -> str:
    result: str = ""
    for i in range(len(s) - 1, -1, -1):
        result += str(s[i])
    return result

def truncate(s: str, max_length: int) -> str:
    if len(s) <= max_length:
        return s
    return str(s[0:max_length]) + "..."

def pluralize(count: int, singular: str, plural: str) -> str:
    if count == 1:
        return f"1 {singular}"
    return f"{count} {plural}"

def title_case(s: str) -> str:
    words: list[str] = s.split(" ")
    result: list[str] = []
    for word in words:
        if len(word) > 0:
            first: str = str(word[0]).upper()
            rest: str = word[1:].lower() if len(word) > 1 else ""
            result.append(first + rest)
        else:
            result.append(word)
    return " ".join(result)

class TextFormatter:
    indent_size: int = 4
    prefix: str = ""

    def __init__(self, prefix: str = ""):
        self.prefix = prefix

    def format_line(self, content: str) -> str:
        if len(self.prefix) > 0:
            return f"{self.prefix} {content}"
        return content

    def format_block(self, lines: list[str]) -> str:
        result: str = ""
        for line in lines:
            if len(result) > 0:
                result += "\n"
            result += self.format_line(line)
        return result
